{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform handling shipment lifecycle from creation through transit to delivery, with weight-based pricing classification.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing bracket assignment.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, with a defined weight and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel is handed to the recipient." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A pricing tier determined by shipment weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no parcel movement without an origin and destination. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a missing or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are unidirectional: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression (e.g., In Transit back to Pending) would corrupt the audit trail and violate the physical reality of parcel movement. This is a state integrity constraint.",
      "testable_assertion": "Transitioning a shipment from In Transit to Pending, or from Delivered to any other state, must be rejected by the system."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state. No further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery is a real-world finality event — the parcel has been handed over. Allowing state changes after delivery corrupts records and breaks downstream processes (invoicing, proof of delivery).",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound is a physical/operational constraint (vehicle capacity, handling equipment limits). Violating either means the data does not represent a real shipment.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 or weight > 1000 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket Standard applies when weight is in the range (0, 10] kg.",
      "invariant": false,
      "invariant_justification": "Bracket boundaries are a business pricing policy. Management could adjust the 10 kg threshold without corrupting system state.",
      "testable_assertion": "A shipment with weight 10 kg must be classified as Standard. A shipment with weight 10.01 kg must not be classified as Standard."
    },
    {
      "id": "BR-6",
      "rule": "Weight bracket Heavy applies when weight is in the range (10, 50] kg.",
      "invariant": false,
      "invariant_justification": "Bracket boundaries are a business pricing policy that can be changed by commercial decision.",
      "testable_assertion": "A shipment with weight 50 kg must be classified as Heavy. A shipment with weight 50.01 kg must not be classified as Heavy."
    },
    {
      "id": "BR-7",
      "rule": "Weight bracket Freight applies when weight is in the range (50, 1000] kg.",
      "invariant": false,
      "invariant_justification": "Bracket boundaries are a business pricing policy that can be changed by commercial decision.",
      "testable_assertion": "A shipment with weight 50.01 kg must be classified as Freight. A shipment with weight 1000 kg must be classified as Freight."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address and a valid delivery address and a weight of 5 kg",
      "when": "A shipment is created",
      "then": "The shipment is created in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A missing pickup address and a valid delivery address",
      "when": "A shipment creation is attempted",
      "then": "The system rejects the request with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A valid pickup address and a missing delivery address",
      "when": "A shipment creation is attempted",
      "then": "The system rejects the request with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment is transitioned to In Transit",
      "then": "The shipment state becomes In Transit"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "The shipment is transitioned to Delivered",
      "then": "The shipment state becomes Delivered"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition the shipment back to Pending",
      "then": "The system rejects the transition and the shipment remains In Transit"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted (to Pending or In Transit)",
      "then": "The system rejects the transition and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A shipment creation request with weight 0 kg",
      "when": "The shipment creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A shipment creation request with weight 1001 kg",
      "when": "The shipment creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight exceeds the 1000 kg maximum"
    },
    {
      "id": "AC-10",
      "given": "A shipment creation request with weight 10 kg",
      "when": "The shipment is created",
      "then": "The shipment is classified in the Standard weight bracket"
    },
    {
      "id": "AC-11",
      "given": "A shipment creation request with weight 25 kg",
      "when": "The shipment is created",
      "then": "The shipment is classified in the Heavy weight bracket"
    },
    {
      "id": "AC-12",
      "given": "A shipment creation request with weight 75 kg",
      "when": "The shipment is created",
      "then": "The shipment is classified in the Freight weight bracket"
    },
    {
      "id": "AC-13",
      "given": "A shipment creation request with weight -5 kg",
      "when": "The shipment creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-14",
      "given": "A shipment in Pending state",
      "when": "An attempt is made to transition directly to Delivered (skipping In Transit)",
      "then": "The system rejects the transition — shipments must pass through In Transit before reaching Delivered"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (Standard/Heavy boundary)", "expected_behavior": "Classified as Standard per the bracket definition '0–10 kg is standard'. The boundary belongs to the lower bracket." },
    { "scenario": "Weight is exactly 50 kg (Heavy/Freight boundary)", "expected_behavior": "Classified as Heavy per the bracket definition '10–50 kg is heavy'. The boundary belongs to the lower bracket." },
    { "scenario": "Weight is exactly 1000 kg", "expected_behavior": "Accepted and classified as Freight. This is the upper limit, not exceeded." },
    { "scenario": "Weight is 0.001 kg (very small but positive)", "expected_behavior": "Accepted and classified as Standard. Weight is positive and within bounds." },
    { "scenario": "Pending shipment attempts direct jump to Delivered", "expected_behavior": "Rejected. The spec implies a linear state machine: Pending → In Transit → Delivered. Skipping In Transit is not described as valid." },
    { "scenario": "Duplicate shipment creation with same addresses", "expected_behavior": "Not specified. The spec does not mention uniqueness constraints on address pairs. Each creation should produce a distinct shipment." },
    { "scenario": "Weight provided with excessive decimal precision (e.g., 10.0000001 kg)", "expected_behavior": "System should define a precision policy. At boundary values, floating-point comparison matters for bracket assignment." },
    { "scenario": "Shipment created with weight exactly 10.0 kg and later weight is corrected to 10.5 kg", "expected_behavior": "Not specified. The spec does not mention whether weight can be updated after creation, or whether bracket reclassification occurs on update." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect bracket assignment means under- or over-charging customers. Boundary errors at 10 kg and 50 kg thresholds are highest risk — a single kilogram difference shifts the pricing tier.",
    "operational": "The unidirectional state machine simplifies warehouse and courier operations — no ambiguity about whether a parcel needs re-pickup. The 1000 kg cap ensures shipments stay within standard logistics equipment capacity.",
    "user": "Clear state transitions give senders and recipients reliable tracking. Terminal Delivered state provides finality and trust. Rejected invalid creations prevent confusion from malformed shipments.",
    "risk": "Boundary ambiguity at 10 kg and 50 kg is the primary financial risk. The spec does not address weight mutability after creation, which could be exploited to game pricing brackets. Missing states (e.g., Cancelled, Failed Delivery, Returned) may force workarounds in real operations.",
    "stakeholders_affected": [
      { "group": "Shippers (Senders)", "impact": "Must provide both addresses and valid weight upfront. Pricing transparency depends on correct bracket assignment." },
      { "group": "Recipients", "impact": "Benefit from reliable delivery finality. Cannot request state rollback after delivery." },
      { "group": "Couriers / Drivers", "impact": "Depend on the state machine for operational clarity. No re-pickup ambiguity once a shipment is in transit." },
      { "group": "Finance / Billing", "impact": "Revenue accuracy depends entirely on correct weight bracket classification. Boundary precision is critical." },
      { "group": "Operations / Dispatch", "impact": "Freight-class shipments (>50 kg) likely require different vehicles and handling — bracket classification triggers operational decisions." },
      { "group": "Customer Support", "impact": "Terminal Delivered state means no system-level recourse for disputes. The absence of Cancelled or Returned states will generate support escalations." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec clearly defines the state machine, weight constraints, and bracket thresholds — those are high confidence. However, several operationally important behaviors are unspecified: whether weight can be updated post-creation, whether Pending→Delivered is a valid skip, whether Cancelled/Returned states exist, and bracket boundary inclusivity (does 10 kg belong to Standard or Heavy). These gaps reduce confidence because implementations will have to make assumptions that could conflict with actual business intent.",
    "high_confidence_areas": [
      "Shipment requires both pickup and delivery addresses",
      "Weight must be positive and ≤ 1000 kg",
      "In Transit cannot revert to Pending",
      "Delivered is terminal and immutable",
      "Three weight brackets exist: Standard, Heavy, Freight"
    ],
    "low_confidence_areas": [
      "Bracket boundary inclusivity — does exactly 10 kg belong to Standard or Heavy?",
      "Whether Pending can skip directly to Delivered",
      "Whether weight is mutable after shipment creation",
      "Absence of Cancelled, Failed Delivery, or Returned states",
      "Whether addresses have any validation beyond presence (format, geocoding)"
    ],
    "assumptions": [
      "Bracket boundaries are inclusive on the lower bracket (10 kg = Standard, 50 kg = Heavy) based on natural reading of 'up to' phrasing",
      "Pending → Delivered is not a valid transition because the spec describes a linear progression",
      "Initial shipment state is Pending (implied but not explicitly stated)",
      "Weight is immutable after shipment creation (not specified, assumed for pricing integrity)",
      "Addresses are required to be non-empty strings; no further format validation is specified"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Bracket boundary inclusivity is not explicit. The spec says '0-10 kg is standard, 10-50 kg is heavy' — 10 kg appears in both ranges. Does a 10.00 kg shipment classify as Standard or Heavy?",
      "affected_stakeholders": ["Finance / Billing", "Shippers (Senders)"],
      "options": ["10 kg inclusive in Standard (upper-bound inclusive)", "10 kg inclusive in Heavy (lower-bound inclusive)"],
      "recommendation": "Adopt upper-bound inclusive convention: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000]. This matches the natural reading of '0-10 kg is standard' and is the most common convention in logistics pricing."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not state whether Pending can transition directly to Delivered, skipping In Transit. This matters for edge cases like local pickups or instant deliveries.",
      "affected_stakeholders": ["Operations / Dispatch", "Couriers / Drivers"],
      "options": ["Allow Pending → Delivered as a valid shortcut", "Enforce strict linear progression: Pending → In Transit → Delivered only"],
      "recommendation": "Enforce strict linear progression. The spec describes a sequential lifecycle and real logistics processes require an In Transit scan for chain-of-custody integrity."
    },
    {
      "type": "missing_context",
      "description": "No Cancelled, Failed Delivery, or Returned states are defined. Real logistics operations routinely encounter these scenarios. Without them, the system cannot model sender cancellations, recipient refusals, or failed delivery attempts.",
      "affected_stakeholders": ["Customer Support", "Shippers (Senders)", "Recipients", "Finance / Billing"],
      "options": ["Add Cancelled and Returned states now", "Defer to a future iteration and document the limitation"],
      "recommendation": "Flag this as a known gap. At minimum, define Cancelled (from Pending only) now to avoid workarounds that corrupt the state machine later."
    },
    {
      "type": "missing_context",
      "description": "The spec does not address whether shipment weight can be updated after creation. If allowed, bracket reclassification and repricing must be handled. If not allowed, this must be enforced.",
      "affected_stakeholders": ["Finance / Billing", "Shippers (Senders)"],
      "options": ["Weight is immutable after creation", "Weight is mutable with bracket reclassification and audit trail"],
      "recommendation": "Make weight immutable after creation for pricing integrity. If correction is needed, require shipment cancellation and re-creation."
    }
  ],

  "rejection_reasons": []
}

